import { cn } from "@/lib/utils";
import type { TodoItem } from "../types";
import { ImageStrip } from "./image-strip";
import { LinkChip } from "./link-chip";
import { PersonChip } from "./person-chip";
import { TimeInfo } from "./time-info";

export function CardBody({ item }: { item: TodoItem }) {
  const hasPeople = item.targetPerson || item.creatorPerson;
  const hasLinks = item.links && item.links.length > 0;
  const hasImages = item.images && item.images.length > 0;

  return (
    <div className="mt-3 space-y-2 text-sm">
      {item.description ? (
        <p className="text-muted-foreground whitespace-pre-wrap">{item.description}</p>
      ) : null}
      <TimeInfo item={item} />
      {hasPeople ? (
        <div className="flex flex-wrap items-center gap-2">
          {item.targetPerson ? (
            <PersonChip person={item.targetPerson} variant="target" />
          ) : null}
          {item.creatorPerson ? (
            <PersonChip person={item.creatorPerson} variant="creator" />
          ) : null}
        </div>
      ) : null}
      {hasLinks ? (
        <div className={cn("flex flex-wrap gap-1.5")}>
          {item.links!.map((link, i) => (
            <LinkChip key={i} link={link} />
          ))}
        </div>
      ) : null}
      {hasImages ? <ImageStrip images={item.images!} /> : null}
    </div>
  );
}

"use client";

import { Badge } from "@/components/ui/badge";
import { useCardContext } from "../hooks/use-card-context";
import type { TodoItem } from "../types";

/**
 * Display-only meta row — priority badge + label chips (v0.3). Reads the item's
 * `priority` / `labels` and their display metadata from context
 * (`priorityOptions` / `labelOptions`). Renders nothing when the item has
 * neither, so cards without these fields are visually unchanged.
 *
 * Colors are applied to border + text only (never a filled background) via
 * inline `style`, so any CSS color string works and an option without a `color`
 * falls back to the themeable `outline` Badge variant. Painting only the
 * dynamic color inline (not the surface) sidesteps the B6 trap where an inline
 * background would beat consumer / theme classes.
 */
export function CardMeta({ item }: { item: TodoItem }) {
  const ctx = useCardContext();
  const priority = item.priority;
  const labels = item.labels ?? [];
  if (!priority && labels.length === 0) return null;

  const priorityOpt = priority
    ? ctx.priorityOptions?.find((o) => o.value === priority)
    : undefined;

  return (
    <div className="mt-2 flex flex-wrap items-center gap-1.5">
      {priority ? (
        <Badge
          variant="outline"
          className="font-medium"
          style={
            priorityOpt?.color
              ? { borderColor: priorityOpt.color, color: priorityOpt.color }
              : undefined
          }
          role="status"
        >
          {priorityOpt?.label ?? priority}
        </Badge>
      ) : null}
      {labels.map((key) => {
        const opt = ctx.labelOptions?.find((o) => o.value === key);
        return (
          <Badge
            key={key}
            variant="outline"
            className="font-normal"
            style={opt?.color ? { borderColor: opt.color, color: opt.color } : undefined}
          >
            {opt?.label ?? key}
          </Badge>
        );
      })}
    </div>
  );
}

"use client";

import { Check, ChevronDown } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { cn } from "@/lib/utils";
import { useCardContext } from "../hooks/use-card-context";
import type { TodoNode } from "../types";

/**
 * Status indicator. Read-only `<Badge>` by default; becomes a status-change
 * dropdown when the card is editable, the item's `edit` permission is granted,
 * `statusEditable` is on, and `statusOptions` is non-empty. The dropdown reuses
 * the exact `edit-field` dispatch + events as the inline editor, so a status
 * change here is identical to one made there.
 */
export function StatusBadge({
  node,
  className,
}: {
  node: TodoNode;
  className?: string;
}) {
  const ctx = useCardContext();
  const status = node.item.status;
  if (!status) return null;

  const options = ctx.statusOptions ?? [];
  const match = options.find((o) => o.value === status);
  const label = match?.label ?? status;
  const variant = match?.variant ?? "secondary";

  // Terminal statuses get a fixed green/red tag regardless of `variant`, so the
  // status reads at a glance (pairs with the card.tsx done/blocked overlay).
  const toneClass =
    match?.tone === "done"
      ? "border-transparent bg-emerald-600 text-white hover:bg-emerald-600/90"
      : match?.tone === "blocked"
        ? "border-transparent bg-rose-600 text-white hover:bg-rose-600/90"
        : "";

  const perms = ctx.resolvePermissions(node);
  const canSelect =
    ctx.statusEditable && ctx.editable && perms.edit && options.length > 0;

  if (!canSelect) {
    return (
      <Badge
        variant={variant}
        className={cn("font-medium", toneClass, className)}
        role="status"
      >
        {label}
      </Badge>
    );
  }

  function selectStatus(next: string) {
    if (next === status) return;
    const id = node.item.id;
    ctx.dispatch({ type: "edit-field", itemId: id, key: "status", value: next });
    ctx.fireEvent("fieldEdited", {
      itemId: id,
      key: "status",
      oldValue: status,
      newValue: next,
    });
    ctx.fireEvent("statusChanged", { itemId: id, oldStatus: status, newStatus: next });
  }

  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        {/* native button + stop-propagation: keeps a click on the badge from
            starting an HTML5/kanban drag or bubbling to the card; data-stop-click
            is honored by the kanban ItemShell's click guard. */}
        <button
          type="button"
          data-stop-click
          onPointerDown={(e) => e.stopPropagation()}
          aria-label={`Status: ${label}. Click to change`}
          className="rounded-full outline-none focus-visible:ring-2 focus-visible:ring-ring"
        >
          <Badge
            variant={variant}
            className={cn("cursor-pointer gap-1 pe-1.5 font-medium", toneClass, className)}
            role="status"
          >
            {label}
            <ChevronDown className="size-3 opacity-70" />
          </Badge>
        </button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="start" className="min-w-36">
        {options.map((opt) => (
          <DropdownMenuItem
            key={opt.value}
            onSelect={() => selectStatus(opt.value)}
            className="gap-2"
          >
            <Check
              className={cn("size-3.5", opt.value === status ? "opacity-100" : "opacity-0")}
            />
            {opt.label}
          </DropdownMenuItem>
        ))}
      </DropdownMenuContent>
    </DropdownMenu>
  );
}

"use client";

import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { cn } from "@/lib/utils";
import type { TodoPerson } from "../types";

function initials(name: string): string {
  // filter(Boolean) drops empty segments so a whitespace-only name yields []
  // (→ "?") and every remaining part is a non-empty string — safe to index.
  const parts = name.trim().split(/\s+/).filter(Boolean);
  if (parts.length === 0) return "?";
  if (parts.length === 1) return parts[0].slice(0, 2).toUpperCase();
  return (parts[0][0] + parts[parts.length - 1][0]).toUpperCase();
}

export function PersonChip({
  person,
  variant = "target",
  className,
}: {
  person: TodoPerson;
  variant?: "target" | "creator";
  className?: string;
}) {
  return (
    <span
      className={cn(
        "inline-flex items-center gap-1.5 rounded-full bg-muted px-2 py-0.5 text-xs",
        className,
      )}
    >
      <Avatar className="size-5">
        {person.avatar ? <AvatarImage src={person.avatar} alt={person.name} /> : null}
        <AvatarFallback className="text-[10px]">{initials(person.name)}</AvatarFallback>
      </Avatar>
      <span className="font-medium">{person.name}</span>
      {variant === "creator" ? (
        <span className="text-muted-foreground">(creator)</span>
      ) : null}
    </span>
  );
}

"use client";

import { ExternalLink, Link as LinkIcon } from "lucide-react";
import { cn } from "@/lib/utils";
import type { TodoLink } from "../types";

function safeHostname(url: string): string {
  try {
    return new URL(url).hostname;
  } catch {
    return url;
  }
}

export function LinkChip({
  link,
  className,
}: {
  link: TodoLink;
  className?: string;
}) {
  const label = link.label ?? safeHostname(link.url);
  let validUrl = true;
  try {
    new URL(link.url);
  } catch {
    validUrl = false;
  }

  if (!validUrl) {
    return (
      <span
        className={cn(
          "inline-flex items-center gap-1 rounded border border-dashed border-destructive/40 px-1.5 py-0.5 text-xs text-muted-foreground",
          className,
        )}
        title="Invalid URL"
      >
        <LinkIcon className="size-3" />
        {label}
      </span>
    );
  }

  return (
    <a
      href={link.url}
      target="_blank"
      rel="noopener noreferrer"
      className={cn(
        "inline-flex items-center gap-1 rounded border border-border bg-card px-1.5 py-0.5 text-xs hover:bg-muted",
        className,
      )}
    >
      {link.icon ? (
        <img src={link.icon} alt="" className="size-3" />
      ) : (
        <LinkIcon className="size-3" />
      )}
      <span className="font-medium">{label}</span>
      <ExternalLink className="size-3 text-muted-foreground" />
    </a>
  );
}

"use client";

import { ScrollArea, ScrollBar } from "@/components/ui/scroll-area";
import { cn } from "@/lib/utils";
