export function ImageStrip({
  images,
  className,
}: {
  images: TodoImage[];
  className?: string;
}) {
  if (images.length === 0) return null;

  return (
    <ScrollArea className={cn("w-full whitespace-nowrap", className)}>
      <div className="flex gap-2 pb-2">
        {images.map((img, i) => (
          <a
            key={i}
            href={img.src}
            target="_blank"
            rel="noopener noreferrer"
            className="block shrink-0"
            title={img.caption}
          >
            <figure className="flex w-32 flex-col gap-1">
              <img
                src={img.src}
                alt={img.alt ?? ""}
                className="h-20 w-32 rounded-md border border-border object-cover"
              />
              {img.caption ? (
                <figcaption className="truncate text-xs text-muted-foreground">
                  {img.caption}
                </figcaption>
              ) : null}
            </figure>
          </a>
        ))}
      </div>
      <ScrollBar orientation="horizontal" />
    </ScrollArea>
  );
}

"use client";

import { Info } from "lucide-react";
import {
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from "@/components/ui/tooltip";
import { useCardContext } from "../hooks/use-card-context";
import type { TodoItem } from "../types";
import { formatAbsolute, formatDuration, formatRelative, parseIso } from "../lib/time";

export function TimeInfo({ item }: { item: TodoItem }) {
  const { now: nowFactory } = useCardContext();
  const now = nowFactory();

  const setAt = parseIso(item.setAt);
  const startAt = parseIso(item.startAt ?? item.setAt);
  const expireAt = parseIso(item.expireAt);

  if (!setAt) return null;

  const primary = (() => {
    if (expireAt) return `Due ${formatRelative(expireAt, now)}`;
    if (item.duration && item.duration > 0)
      return `Duration: ${formatDuration(item.duration)}`;
    return null;
  })();

  return (
    <TooltipProvider>
      <div className="flex items-center gap-2 text-xs text-muted-foreground">
        {primary ? <span className="font-medium">{primary}</span> : null}
        <Tooltip>
          <TooltipTrigger asChild>
            <button
              type="button"
              className="inline-flex items-center text-muted-foreground/70 hover:text-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring rounded"
              aria-label="Show timing details"
            >
              <Info className="size-3" />
            </button>
          </TooltipTrigger>
          <TooltipContent side="top" className="max-w-xs">
            <dl className="grid grid-cols-[auto_1fr] gap-x-3 gap-y-1 text-xs">
              <dt className="text-muted-foreground">Created</dt>
              <dd>{formatAbsolute(setAt)}</dd>
              <dt className="text-muted-foreground">Starts</dt>
              <dd>{startAt ? formatAbsolute(startAt) : formatAbsolute(setAt)}</dd>
              <dt className="text-muted-foreground">Expires</dt>
              <dd>{expireAt ? formatAbsolute(expireAt) : "—"}</dd>
              {item.duration && item.duration > 0 ? (
                <>
                  <dt className="text-muted-foreground">Duration</dt>
                  <dd>{formatDuration(item.duration)}</dd>
                </>
              ) : null}
            </dl>
          </TooltipContent>
        </Tooltip>
      </div>
    </TooltipProvider>
  );
}

"use client";

import {
  ClipboardPaste,
  Copy,
  Edit3,
  Lock,
  MoreHorizontal,
  Palette,
  PanelTop,
  PowerOff,
  Trash2,
  Unlock,
  Zap,
} from "lucide-react";
import { Button } from "@/components/ui/button";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { useCardContext } from "../hooks/use-card-context";
import { copyTasksToClipboard, readTasksFromClipboard } from "../lib/clipboard";
import { denormalize } from "../lib/normalize";
import type { TodoNode } from "../types";

export function ActionMenu({
  node,
  onOverrideColor,
}: {
  node: TodoNode;
  onOverrideColor: () => void;
}) {
  const ctx = useCardContext();
  const perms = ctx.resolvePermissions(node);
  const id = node.item.id;
  const isInlineActive = ctx.editState.kind === "inline" && ctx.editState.itemId === id;

  function tryOpenEdit(mode: "popup" | "inline") {
    if (!perms.edit) {
      ctx.reportPermissionDenied("edit", id, perms.reason);
      return;
    }
    ctx.dispatch({ type: "open-edit", itemId: id, mode });
    ctx.fireEvent("editRequest", { itemId: id, mode });
  }

  async function handleCopy() {
    // Denormalize so the copied subtree's `children` is current; the shared
    // clipboard writes the typed MIME and falls back to text/plain.
    try {
      const item = denormalize(node);
      await copyTasksToClipboard([item], "todo-rich-card");
      ctx.fireEvent("copy", { itemId: id, payload: item });
    } catch (err) {
      console.warn("[todo-rich-card] copy failed", err);
    }
  }

  async function handlePaste() {
    if (!perms.addChildren) {
      ctx.reportPermissionDenied("addChildren", id, perms.reason);
      return;
    }
    const items = await readTasksFromClipboard();
    if (!items) return;
    for (const payload of items) {
      ctx.dispatch({ type: "add-child", parentId: id, item: payload });
      ctx.fireEvent("paste", { parentId: id, payload });
      ctx.fireEvent("itemAdded", { parentId: id, item: payload });
    }
  }

  function handleToggleActive() {
    if (!perms.toggleActive) {
      ctx.reportPermissionDenied("toggleActive", id, perms.reason);
      return;
    }
    const oldActive = node.item.active;
    ctx.dispatch({ type: "toggle-active", itemId: id });
    ctx.fireEvent("activeToggled", {
      itemId: id,
      oldActive,
      newActive: !oldActive,
    });
    ctx.fireEvent("fieldEdited", {
      itemId: id,
      key: "active",
      oldValue: oldActive,
      newValue: !oldActive,
    });
  }

  function handleToggleLocked() {
    const oldLocked = Boolean(node.item.locked);
    ctx.dispatch({ type: "set-locked", itemId: id, locked: !oldLocked });
    ctx.fireEvent("lockedToggled", {
      itemId: id,
      oldLocked,
      newLocked: !oldLocked,
    });
  }

  function handleRemove() {
    if (!perms.remove) {
      ctx.reportPermissionDenied("remove", id, perms.reason);
      return;
    }
    ctx.dispatch({ type: "remove-item", itemId: id });
    ctx.fireEvent("itemRemoved", {
      itemId: id,
      removed: node.item,
      parentId: node.parentId ?? id,
    });
  }

  function handleOverrideColor() {
    if (!perms.overrideColor) {
      ctx.reportPermissionDenied("overrideColor", id, perms.reason);
      return;
    }
    onOverrideColor();
  }

  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <Button
          variant="ghost"
          size="icon"
          className="size-6"
          aria-label="Card actions"
        >
          <MoreHorizontal className="size-3.5" />
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="end" className="w-52">
        <DropdownMenuItem
          disabled={!perms.edit}
          onClick={() => tryOpenEdit(ctx.editable ? "inline" : "popup")}
        >
          <Edit3 className="mr-2 size-4" />
          {ctx.editable && isInlineActive ? "Close inline edit" : "Edit"}
        </DropdownMenuItem>
        {ctx.editable ? (
          <DropdownMenuItem
            disabled={!perms.edit}
            onClick={() => tryOpenEdit("popup")}
          >
            <PanelTop className="mr-2 size-4" />
            Edit in dialog…
          </DropdownMenuItem>
        ) : null}
        <DropdownMenuSeparator />
        <DropdownMenuItem onClick={handleCopy}>
          <Copy className="mr-2 size-4" />
          Copy
        </DropdownMenuItem>
        <DropdownMenuItem
          disabled={!perms.addChildren}
          onClick={handlePaste}
        >
          <ClipboardPaste className="mr-2 size-4" />
          Paste as child
        </DropdownMenuItem>
        <DropdownMenuSeparator />
        <DropdownMenuItem
          disabled={!perms.toggleActive}
          onClick={handleToggleActive}
        >
          {node.item.active ? (
            <>
              <PowerOff className="mr-2 size-4" />
              Deactivate
            </>
          ) : (
            <>
              <Zap className="mr-2 size-4" />
              Activate
            </>
          )}
        </DropdownMenuItem>
        <DropdownMenuItem onClick={handleToggleLocked}>
          {node.item.locked ? (
            <>
              <Unlock className="mr-2 size-4" />
              Unlock
            </>
          ) : (
            <>
              <Lock className="mr-2 size-4" />
              Lock
            </>
          )}
        </DropdownMenuItem>
        <DropdownMenuItem
          disabled={!perms.overrideColor}
          onClick={handleOverrideColor}
        >
          <Palette className="mr-2 size-4" />
          Override color…
        </DropdownMenuItem>
        <DropdownMenuSeparator />
        <DropdownMenuItem
          disabled={!perms.remove}
          onClick={handleRemove}
          className="text-destructive focus:text-destructive"
        >
          <Trash2 className="mr-2 size-4" />
          Remove
        </DropdownMenuItem>
      </DropdownMenuContent>
    </DropdownMenu>
  );
}

