import { useState } from "react";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Switch } from "@/components/ui/switch";
import { Textarea } from "@/components/ui/textarea";
import { Separator } from "@/components/ui/separator";
import { useCardContext } from "../hooks/use-card-context";
import type { TodoEditableField, TodoItem, TodoNode } from "../types";

function isoToDatetimeLocal(iso: string | undefined): string {
  if (!iso) return "";
  const d = new Date(iso);
  if (!Number.isFinite(d.getTime())) return "";
  // datetime-local expects "YYYY-MM-DDTHH:mm" in local time.
  const pad = (n: number) => String(n).padStart(2, "0");
  return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}T${pad(d.getHours())}:${pad(d.getMinutes())}`;
}

function datetimeLocalToIso(local: string): string | undefined {
  if (!local) return undefined;
  const d = new Date(local);
  return Number.isFinite(d.getTime()) ? d.toISOString() : undefined;
}

type Draft = {
  name: string;
  description: string;
  status: string;
  active: boolean;
  setAt: string;
  startAt: string;
  expireAt: string;
  duration: string;
};

function itemToDraft(item: TodoItem): Draft {
  return {
    name: item.name,
    description: item.description ?? "",
    status: item.status,
    active: item.active,
    setAt: isoToDatetimeLocal(item.setAt),
    startAt: isoToDatetimeLocal(item.startAt),
    expireAt: isoToDatetimeLocal(item.expireAt),
    duration:
      item.duration != null && Number.isFinite(item.duration)
        ? String(Math.round(item.duration / 1000 / 60))
        : "",
  };
}

export function EditPopup({ node }: { node: TodoNode }) {
  const ctx = useCardContext();
  const isOpen =
    ctx.editState.kind === "popup" && ctx.editState.itemId === node.item.id;
  const [draft, setDraft] = useState<Draft>(() => itemToDraft(node.item));
  const [originalId, setOriginalId] = useState<string>(node.item.id);

  // Reset draft when the dialog reopens for a (possibly different) item.
  if (isOpen && originalId !== node.item.id) {
    setOriginalId(node.item.id);
    setDraft(itemToDraft(node.item));
  }

  function setField<K extends keyof Draft>(key: K, value: Draft[K]) {
    setDraft((prev) => ({ ...prev, [key]: value }));
  }

  function applyDraft() {
    const id = node.item.id;
    const item = node.item;

    function emit<K extends TodoEditableField>(
      key: K,
      oldValue: unknown,
      newValue: unknown,
    ) {
      if (Object.is(oldValue, newValue)) return;
      ctx.dispatch({ type: "edit-field", itemId: id, key, value: newValue });
      ctx.fireEvent("fieldEdited", { itemId: id, key, oldValue, newValue });
    }

    emit("name", item.name, draft.name);
    emit("description", item.description ?? "", draft.description);

    if (draft.status !== item.status) {
      const oldStatus = item.status;
      emit("status", oldStatus, draft.status);
      ctx.fireEvent("statusChanged", {
        itemId: id,
        oldStatus,
        newStatus: draft.status,
      });
    }

    if (draft.active !== item.active) {
      emit("active", item.active, draft.active);
      ctx.fireEvent("activeToggled", {
        itemId: id,
        oldActive: item.active,
        newActive: draft.active,
      });
    }

    emit("setAt", item.setAt, datetimeLocalToIso(draft.setAt) ?? item.setAt);
    emit("startAt", item.startAt, datetimeLocalToIso(draft.startAt));
    emit("expireAt", item.expireAt, datetimeLocalToIso(draft.expireAt));

    const durMinutes = draft.duration === "" ? null : Number(draft.duration);
    const durMs =
      durMinutes != null && Number.isFinite(durMinutes) && durMinutes > 0
        ? durMinutes * 60 * 1000
        : undefined;
    emit("duration", item.duration, durMs);

    ctx.dispatch({ type: "close-edit" });
  }

  function handleOpenChange(open: boolean) {
    if (!open) ctx.dispatch({ type: "close-edit" });
  }

  return (
    <Dialog open={isOpen} onOpenChange={handleOpenChange}>
      <DialogContent className="max-w-lg">
        <DialogHeader>
          <DialogTitle>Edit task</DialogTitle>
          <DialogDescription>
            Changes apply when you click Save. Press Escape to discard.
          </DialogDescription>
        </DialogHeader>

        <div className="grid gap-4 py-2">
          <div className="grid gap-1.5">
            <Label htmlFor="todo-name">Name</Label>
            <Input
              id="todo-name"
              value={draft.name}
              onChange={(e) => setField("name", e.target.value)}
            />
          </div>

          <div className="grid gap-1.5">
            <Label htmlFor="todo-description">Description</Label>
            <Textarea
              id="todo-description"
              rows={3}
              value={draft.description}
              onChange={(e) => setField("description", e.target.value)}
            />
          </div>

          <div className="grid grid-cols-2 gap-3">
            <div className="grid gap-1.5">
              <Label htmlFor="todo-status">Status</Label>
              {ctx.statusOptions && ctx.statusOptions.length > 0 ? (
                <Select
                  value={draft.status}
                  // Cross-backend: Radix passes `(string)`, Base UI passes
                  // `(string | null, eventDetails)` — keep the nullable guard.
                  onValueChange={(v: string | null) => setField("status", v ?? "")}
                >
                  {/* w-full override per F-cross-13 / shadcn v4 Select w-fit lock */}
                  <SelectTrigger id="todo-status" className="w-full">
                    <SelectValue placeholder="Select status" />
                  </SelectTrigger>
                  <SelectContent>
                    {ctx.statusOptions.map((opt) => (
                      <SelectItem key={opt.value} value={opt.value}>
                        {opt.label}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              ) : (
                <Input
                  id="todo-status"
                  value={draft.status}
                  onChange={(e) => setField("status", e.target.value)}
                />
              )}
            </div>
            <div className="grid gap-1.5">
              <Label htmlFor="todo-active" className="flex items-center justify-between">
                <span>Active</span>
                <Switch
                  id="todo-active"
                  checked={draft.active}
                  onCheckedChange={(v) => setField("active", v)}
                />
              </Label>
            </div>
          </div>

          <Separator />

          <div className="grid grid-cols-2 gap-3">
            <div className="grid gap-1.5">
              <Label htmlFor="todo-setAt">Set at</Label>
              <Input
                id="todo-setAt"
                type="datetime-local"
                value={draft.setAt}
                onChange={(e) => setField("setAt", e.target.value)}
              />
            </div>
            <div className="grid gap-1.5">
              <Label htmlFor="todo-startAt">Starts at</Label>
              <Input
                id="todo-startAt"
                type="datetime-local"
                value={draft.startAt}
                onChange={(e) => setField("startAt", e.target.value)}
              />
            </div>
            <div className="grid gap-1.5">
              <Label htmlFor="todo-expireAt">Expires at</Label>
              <Input
                id="todo-expireAt"
                type="datetime-local"
                value={draft.expireAt}
                onChange={(e) => setField("expireAt", e.target.value)}
              />
            </div>
            <div className="grid gap-1.5">
              <Label htmlFor="todo-duration">Duration (min)</Label>
              <Input
                id="todo-duration"
                type="number"
                min={0}
                placeholder="e.g. 30"
                value={draft.duration}
                onChange={(e) => setField("duration", e.target.value)}
              />
            </div>
          </div>
        </div>

        <DialogFooter>
          <Button
            variant="ghost"
            onClick={() => ctx.dispatch({ type: "close-edit" })}
          >
            Cancel
          </Button>
          <Button onClick={applyDraft}>Save</Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

"use client";

import { useState } from "react";
import { Check, X } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Textarea } from "@/components/ui/textarea";
import { useCardContext } from "../hooks/use-card-context";
import type { TodoEditableField, TodoItem, TodoNode } from "../types";

/**
 * Inline editor. Each field commits on blur (or Enter for text fields) via
 * edit-field dispatch — no Save button. Escape (handled at the card level)
 * closes inline mode without rollback.
 *
 * Images / links are read-only in inline mode (per plan §6.3); consumers
 * needing to edit those use the popup.
 */
export function EditInline({ node }: { node: TodoNode }) {
  const ctx = useCardContext();
  const id = node.item.id;

  function commit<K extends TodoEditableField>(
    key: K,
    oldValue: unknown,
    newValue: unknown,
  ) {
    if (Object.is(oldValue, newValue)) return;
    ctx.dispatch({ type: "edit-field", itemId: id, key, value: newValue });
    ctx.fireEvent("fieldEdited", { itemId: id, key, oldValue, newValue });
    if (key === "status") {
      ctx.fireEvent("statusChanged", {
        itemId: id,
        oldStatus: oldValue as string,
        newStatus: newValue as string,
      });
    }
  }

  return (
    // Stop pointer propagation so dragging to select text inside a field doesn't
    // start a kanban/HTML5 card drag when this card is embedded with shell-drag.
    <div
      className="space-y-2 rounded-md border border-dashed border-border bg-muted/30 p-3"
      onPointerDown={(e) => e.stopPropagation()}
    >
      <NameField item={node.item} commit={commit} />
      <DescriptionField item={node.item} commit={commit} />
      <StatusField item={node.item} commit={commit} />
      <div className="flex justify-end">
        <Button
          variant="ghost"
          size="sm"
          className="gap-1"
          onClick={() => ctx.dispatch({ type: "close-edit" })}
        >
          <X className="size-3.5" />
          Done editing
        </Button>
      </div>
    </div>
  );
}

function NameField({
  item,
  commit,
}: {
  item: TodoItem;
  commit: <K extends TodoEditableField>(key: K, oldValue: unknown, newValue: unknown) => void;
}) {
  const [value, setValue] = useState(item.name);

  return (
    <div className="flex items-center gap-1">
      <Input
        autoFocus
        value={value}
        onChange={(e) => setValue(e.target.value)}
        onBlur={() => commit("name", item.name, value)}
        onKeyDown={(e) => {
          if (e.key === "Enter") {
            e.preventDefault();
            (e.currentTarget as HTMLInputElement).blur();
          }
        }}
        className="font-medium"
        aria-label="Name"
      />
    </div>
  );
}

function DescriptionField({
  item,
  commit,
}: {
  item: TodoItem;
  commit: <K extends TodoEditableField>(key: K, oldValue: unknown, newValue: unknown) => void;
}) {
  const [value, setValue] = useState(item.description ?? "");

  return (
    <Textarea
      rows={2}
      placeholder="Description"
      value={value}
      onChange={(e) => setValue(e.target.value)}
      onBlur={() => commit("description", item.description ?? "", value)}
      className="resize-none"
      aria-label="Description"
    />
  );
}

function StatusField({
  item,
  commit,
}: {
  item: TodoItem;
  commit: <K extends TodoEditableField>(key: K, oldValue: unknown, newValue: unknown) => void;
}) {
  const ctx = useCardContext();
  const [value, setValue] = useState(item.status);
  const opts = ctx.statusOptions;

  if (opts && opts.length > 0) {
    return (
      <Select
        value={value}
        // Cross-backend signature: the producer's Radix Select passes `(string)`,
        // but a Base UI (base-nova) consumer's Select passes
        // `(string | null, eventDetails)`. Keep the nullable param + `?? ""` guard
        // so this handler stays assignable to BOTH backends (smoke-proven).
        onValueChange={(v: string | null) => {
          const next = v ?? "";
          setValue(next);
          commit("status", item.status, next);
        }}
      >
        {/* w-full override per F-cross-13 / shadcn v4 Select w-fit lock */}
        <SelectTrigger className="w-full" aria-label="Status">
          <SelectValue placeholder="Status" />
        </SelectTrigger>
        <SelectContent>
          {opts.map((opt) => (
            <SelectItem key={opt.value} value={opt.value}>
              {opt.label}
            </SelectItem>
          ))}
        </SelectContent>
      </Select>
    );
  }

  return (
    <div className="flex items-center gap-1">
      <Input
        placeholder="Status"
        value={value}
        onChange={(e) => setValue(e.target.value)}
        onBlur={() => commit("status", item.status, value)}
        onKeyDown={(e) => {
          if (e.key === "Enter") {
            e.preventDefault();
            (e.currentTarget as HTMLInputElement).blur();
          }
        }}
        aria-label="Status"
      />
      <Check className="size-3.5 text-muted-foreground" />
    </div>
  );
}

"use client";

/**
 * Kanban-board renderer adapter (plan Q-P6).
 *
 * Exposes `todoRichCardKanbanRenderer`: a `KanbanCardRenderer<TodoItem>` that
 * `kanban-board-01` can register and use as the body for each card slot.
 *
 * `dragHandle: "shell"` (v0.3): the whole card is the drag activator. The rich
 * card normally marks its root `draggable` (HTML5 DnD, for copy/move payload +
 * nested drop), which would hijack the kanban PointerSensor gesture — so the
 * adapter passes `canDragItem={() => false}` to disable the root `draggable`
 * while embedded, letting the two DnD systems coexist. The board's
 * `activationConstraint: { distance: 5 }` keeps a click on an inner control
 * (status, edit, switch) from becoming a drag, and the inline editor stops
 * pointer propagation so text selection in a field doesn't drag the card.
 *
 * Trade-off: with the root drag disabled, subtasks can't be reordered by native
 * DnD *inside a kanban column* — acceptable since the kanban owns movement
 * there; the standalone (list) card keeps its internal DnD.
 *
 * NOTE: this adapter renders a SINGLE TodoRichCard per kanban item. The item's
 * own `children` still recurse internally — kanban "items" are not the same
 * as todo "children." Consumers wiring deep nesting into kanban columns should
 * flatten to one level at the kanban level and keep the depth inside each
 * card.
 */

import { TodoRichCard } from "../todo-rich-card";
import type { TodoItem } from "../types";

/**
 * Minimal structural mirror of `kanban-board-01`'s `KanbanCardRenderer<TData>`.
 * Declared inline to avoid a hard cross-procomp import (consumers wiring this
 * adapter into kanban-board-01 will get full type checking through that
 * procomp's own re-exported type).
 */
type KanbanRenderContext = {
  itemId: string;
  columnId: string;
  swimlaneId?: string;
  isDragging: boolean;
  isLocked: boolean;
  /** Persist an in-place edit back to the board (kanban-board-01 v0.4+). */
  onDataChange?: (nextData: unknown) => void;
};

type KanbanCardRenderer<TData> = {
  id: string;
  label: string;
  render: (data: TData, ctx: KanbanRenderContext) => React.ReactNode;
  newItem?: () => TData;
  editForm?: (
    data: TData,
    onSave: (next: TData) => void,
    onCancel: () => void,
  ) => React.ReactNode;
  dragHandle?: "shell" | "header";
};

export const todoRichCardKanbanRenderer: KanbanCardRenderer<TodoItem> = {
  id: "todo-rich-card",
  label: "Todo (rich)",
  dragHandle: "shell",
  // Controlled: the board's item data is the source of truth. Edits flow back
  // via onChange → ctx.onDataChange so they persist; a locked item is read-only;
  // `key` resets card state when the board swaps the item in this slot.
  // `canDragItem={() => false}` disables the card's own root `draggable` so it
  // can't hijack the board's pointer drag (see file header).
  render: (data, ctx) => (
    <TodoRichCard
      key={ctx.itemId}
      value={data}
      editable={!ctx.isLocked}
      canDragItem={() => false}
      onChange={(next) => ctx.onDataChange?.(next)}
    />
  ),
  newItem: () => ({
    id: `todo-${Date.now().toString(36)}`,
    name: "New task",
    status: "todo",
    active: true,
    setAt: new Date().toISOString(),
  }),
};
